import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F06: 存貨與債務穩定度審計","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F06_存貨與債務穩定度審計.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F06_存貨與債務穩定度審計.md"}'),r={name:"審計報告庫/財務審計/6442_光聖/20260504/F06_存貨與債務穩定度審計.md"};function d(s,t,i,o,g,c){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="f06-存貨與債務穩定度審計" tabindex="-1">F06: 存貨與債務穩定度審計 <a class="header-anchor" href="#f06-存貨與債務穩定度審計" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p><hr><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨週轉 663→347 天持續改善、現金循環 519→280 天縮短；現金 74.9 億覆蓋流動負債 40 億達 187%，速動比率 238%，流動性無虞，整體評級低風險。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新年報數據</li></ul><hr><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>存貨總額從 602M（2023）→ 1,191M（2024, +98%）→ 1,209M（2025, +1.5%），營收同期倍增但存貨幾乎凍結，管理效率顯著提升。庫存結構中製成品從 557M 降至 473M（−15%），原料從 454M 升至 519M（+14%），顯示成品去化順暢而備料積極。現金循環從 519 天降至 280 天，流動比率從 214%→231%→269%，各項流動性指標均處頂尖水準。</p><p><strong>評級：S（優）</strong> — 存貨效率大幅改善，流動性極充裕。</p><hr><h2 id="🔍-答詢詳解-200-450-字" tabindex="-1">🔍 答詢詳解（200-450 字） <a class="header-anchor" href="#🔍-答詢詳解-200-450-字" aria-label="Permalink to &quot;🔍 答詢詳解（200-450 字）&quot;">​</a></h2><h3 id="_1-庫存週轉與現金循環效率" tabindex="-1">1. 庫存週轉與現金循環效率 <a class="header-anchor" href="#_1-庫存週轉與現金循環效率" aria-label="Permalink to &quot;1. 庫存週轉與現金循環效率&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">2023</th><th style="text-align:center;">2024</th><th style="text-align:center;">2025</th><th style="text-align:center;">趨勢</th></tr></thead><tbody><tr><td style="text-align:left;">存貨（千元）</td><td style="text-align:center;">602,362</td><td style="text-align:center;">1,190,671</td><td style="text-align:center;">1,209,369</td><td style="text-align:center;">持平</td></tr><tr><td style="text-align:left;">存貨週轉天數</td><td style="text-align:center;">663 天</td><td style="text-align:center;">379 天</td><td style="text-align:center;">347 天</td><td style="text-align:center;">↓改善</td></tr><tr><td style="text-align:left;">應收天數（DSO）</td><td style="text-align:center;">62 天</td><td style="text-align:center;">68 天</td><td style="text-align:center;">56 天</td><td style="text-align:center;">↓改善</td></tr><tr><td style="text-align:left;">應付天數（DPO）</td><td style="text-align:center;">206 天</td><td style="text-align:center;">95 天</td><td style="text-align:center;">123 天</td><td style="text-align:center;">↑提高</td></tr><tr><td style="text-align:left;"><strong>現金循環天數</strong></td><td style="text-align:center;"><strong>519 天</strong></td><td style="text-align:center;"><strong>352 天</strong></td><td style="text-align:center;"><strong>280 天</strong></td><td style="text-align:center;"><strong>↓大幅改善</strong></td></tr></tbody></table><p>2023 年存貨週轉高達 663 天主因為營收基期低（2.58B）且庫存水位相對高（602M），隨營收暴增至 10.71B，庫存僅微增至 1,209M，週轉天數自然快速下降。2025 年現金循環 280 天（約 9 個月），雖仍偏長但已從高峰大幅改善。</p><p><strong>存貨明細變動（2024→2025）：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">類別</th><th style="text-align:center;">2024</th><th style="text-align:center;">2025</th><th style="text-align:center;">變動</th></tr></thead><tbody><tr><td style="text-align:left;">原物料</td><td style="text-align:center;">453,590</td><td style="text-align:center;">519,151</td><td style="text-align:center;">+14.5%</td></tr><tr><td style="text-align:left;">在製品</td><td style="text-align:center;">179,877</td><td style="text-align:center;">217,528</td><td style="text-align:center;">+20.9%</td></tr><tr><td style="text-align:left;">製成品</td><td style="text-align:center;">557,204</td><td style="text-align:center;">472,690</td><td style="text-align:center;"><strong>−15.2%</strong></td></tr><tr><td style="text-align:left;"><strong>合計</strong></td><td style="text-align:center;"><strong>1,190,671</strong></td><td style="text-align:center;"><strong>1,209,369</strong></td><td style="text-align:center;"><strong>+1.6%</strong></td></tr></tbody></table><p>製成品下降是存貨管理的核心亮點——營收倍增的同時成品庫存反而減少，代表拉貨動能強勁、庫存去化效率極高。原料與在製品增加則反映對 2026 年訂單的備料信心。</p><h3 id="_2-償債能力測試" tabindex="-1">2. 償債能力測試 <a class="header-anchor" href="#_2-償債能力測試" aria-label="Permalink to &quot;2. 償債能力測試&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">2023</th><th style="text-align:center;">2024</th><th style="text-align:center;">2025</th><th style="text-align:center;">標準</th></tr></thead><tbody><tr><td style="text-align:left;">流動比率</td><td style="text-align:center;">214%</td><td style="text-align:center;">231%</td><td style="text-align:center;"><strong>269%</strong></td><td style="text-align:center;">&gt;200% 優</td></tr><tr><td style="text-align:left;">速動比率</td><td style="text-align:center;">155%</td><td style="text-align:center;">177%</td><td style="text-align:center;"><strong>238%</strong></td><td style="text-align:center;">&gt;100% 優</td></tr><tr><td style="text-align:left;">現金 / 流動負債</td><td style="text-align:center;">97%</td><td style="text-align:center;">123%</td><td style="text-align:center;"><strong>187%</strong></td><td style="text-align:center;">&gt;100% 優</td></tr><tr><td style="text-align:left;">負債比率</td><td style="text-align:center;">38.7%</td><td style="text-align:center;">44.3%</td><td style="text-align:center;">49.0%</td><td style="text-align:center;">安全</td></tr><tr><td style="text-align:left;">應付公司債</td><td style="text-align:center;">0</td><td style="text-align:center;">935M</td><td style="text-align:center;">2,348M</td><td style="text-align:center;">CB 膨脹</td></tr></tbody></table><p>2025 年末現金 74.9 億，遠超流動負債 40.0 億，即使不計其他流動資產，單靠現金即可覆蓋全部短期債務的 1.87 倍。2.35B 的可轉換公司債為非流動負債，若全數轉換將稀釋股權但不構成現金流壓力。總負債比 49% 雖較 2023 年的 38.7% 上升，但主因為 CB 發行，屬結構性而非營運風險。</p><h3 id="_3-跌價損失準備" tabindex="-1">3. 跌價損失準備 <a class="header-anchor" href="#_3-跌價損失準備" aria-label="Permalink to &quot;3. 跌價損失準備&quot;">​</a></h3><p>2025 年提列存貨跌價損失 4,439 萬，對比存貨總額 12.09 億，準備率 3.7%。2024 年提列 2,680 萬（準備率 2.3%），2025 年提列金額增加 66%，反映管理層在存貨管理改善的同時採取了更審慎的評價政策。</p><hr><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><p><strong>現金循環仍高達 280 天（壓力 ⚠️）</strong>：雖然從 519 天顯著改善，但 280 天的現金循環仍意味著從進料付款到收款需要約 9 個月。若成長動能放緩，營運資金需求可能重新惡化，壓縮 FCF 增長空間。對比同業（如台達電約 80-120 天），光聖在供應鏈效率上仍有大幅改善空間。</p></li><li><p><strong>可轉換公司債 23.5 億的長期稀釋壓力</strong>：2025 年末 CB 餘額 23.5 億，若按轉換價全數轉換，將新增大量流通股數，稀釋現有股東權益 15-20%。若股價低於轉換價導致 CB 持有者選擇贖回，將產生一次性現金流出壓力。</p></li><li><p><strong>存貨跌價準備仍可能不足</strong>：347 天的庫存週轉意味著部分原料在倉 1 年以上未產出。特別是 5.19 億的原物料，若產品世代迭代（如從 288 芯→6,912 芯），舊規格原料可能面臨製成呆料的跌價風險，3.7% 的準備率未必充分。</p></li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><p><strong>製成品去化順暢驗證下游需求真實性</strong>：營收倍增而製成品存貨反降 15%，證明拉貨是真實的終端需求而非通路塞貨，管理層聲稱的「出貨正常穩定」有數據支撐。</p></li><li><p><strong>現金水位極高，具備快速去槓桿能力</strong>：74.9 億現金可隨時清償全部短期負債 40 億及大部分 CB 負債（23.5 億），財務韌性具壓倒性優勢。</p></li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>光聖的存貨管理在 2024-2025 年經歷了質的飛躍，流動性處於台股製造業前 10% 水準。唯一需持續關注的是高額現金的運用效率與 CB 的轉換進度。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (inventory_check 6442)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet</li><li><strong>原始數據</strong>：FinMind TaiwanStockMonthRevenue</li><li><strong>年報資料</strong>：6442 2025 Q4 合併財報存貨明細附註（製成品/在製品/原物料明細，存貨跌價損失）</li><li><strong>查詢參數</strong>：stock_id=6442, start=2023-01-01, end=2025-12-31</li><li><strong>數據查詢日期</strong>：2026-05-04</li></ul>',37)])])}const y=e(r,[["render",d]]);export{x as __pageData,y as default};
